// Compliant: Promise with proper exception handling
struct GoodPromise {
    auto initial_suspend() { return std::suspend_never{}; }
    auto final_suspend() noexcept { return std::suspend_never{}; }
    auto return_void() {}
    auto get_return_object() { return Task{*this}; }

    void unhandled_exception() {
        exception_ = std::current_exception();
    }

private:
    std::exception_ptr exception_;
};

// Compliant: Proper exception handling
cppcoro::task<int> safeOperation() {
    try {
        auto result = co_await dangerousAsyncCall();
        co_return result.getValue();
    } catch (const std::exception& e) {
        logError(e.what());
        co_return -1; // Safe fallback
    }
}
